#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_global_int32_base_atomics : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

inline float atomic_add_float(__global float* addr, float val) {
    union {
        unsigned int u;
        float f;
    } old_val, new_val;
    do {
        old_val.u = atomic_load((volatile __global unsigned int*)addr);
        new_val.f = old_val.f + val;
    } while (atomic_cmpxchg((volatile __global unsigned int*)addr, old_val.u, as_uint(new_val.f)) != old_val.u);
    return new_val.f;
}

__kernel void pgain_kernel(
    __global Point_Struct* p,
    __global float* coord,
    __global float* work_mem,
    __global int* center_table,
    __global char* switch_membership,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    float x_cost = 0.0f;
    float current_cost = p[i].cost;

    // Compute distance between point i and point x
    float dist_val = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i * dim + d] - coord[x * dim + d];
        dist_val += diff * diff;
    }
    x_cost = dist_val * p[i].weight;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1)] = x_cost - current_cost;
    } else {
        int assign = p[i].assign;
        // Atomic add to work_mem at center_table[assign] + i*(K+1)
        atomic_add_float(&work_mem[center_table[assign] + i * (K + 1)], current_cost - x_cost);
        switch_membership[i] = 0;
    }
}

